@push('scripts')<script>const landmarks=document.getElementById('landmarks');document.getElementById('addLandmark').addEventListener('click',()=>landmarks.insertAdjacentHTML('beforeend','<div class="landmark-row flex gap-2"><input name="landmarks[]" class="h-10 flex-1 rounded-xl border-slate-200 text-sm" placeholder="Near metro, college or hospital"><button type="button" class="remove-landmark rounded-xl bg-red-50 px-3 text-red-600"><i class="fas fa-trash"></i></button></div>'));landmarks.addEventListener('click',event=>{const button=event.target.closest('.remove-landmark');if(button&&landmarks.querySelectorAll('.landmark-row').length>1)button.closest('.landmark-row').remove();else if(button)button.closest('.landmark-row').querySelector('input').value=''});const photos=document.getElementById('roomPhotos');photos.addEventListener('change',()=>{const preview=document.getElementById('photoPreview'),label=document.getElementById('photoSelection'),files=[...photos.files];preview.innerHTML='';if(files.length>5){photos.value='';label.textContent='Select no more than 5 photos.';label.className='mt-2 text-[10px] font-bold text-red-600';return}label.className='mt-2 text-[10px] text-slate-500';label.textContent=files.length?`${files.length} photo(s) selected. The first will be the cover.`:'No photos selected.';files.forEach(file=>{const image=document.createElement('img');image.src=URL.createObjectURL(file);image.className='preview-image';preview.appendChild(image)})});</script>@endpush
